import{_ as e,o as n,c as s,a3 as t}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Kafka 存储机制","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/storage.md","filePath":"middleware/kafka/storage.md","lastUpdated":1783394230000}'),p={name:"middleware/kafka/storage.md"};function d(l,a,i,o,c,r){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="kafka-cun-chu-ji-zhi" tabindex="-1">Kafka 存储机制 <a class="header-anchor" href="#kafka-cun-chu-ji-zhi" aria-label="Permalink to &quot;Kafka 存储机制&quot;">​</a></h1><p>Kafka 的核心不是把消息暂存在内存里，而是把消息持久化为磁盘上的<strong>追加日志</strong>。每个 Topic 被拆成多个 Partition，每个 Partition 在 Broker 上对应一个日志目录，消息按 Offset 递增追加写入。</p><h2 id="cun-chu-ceng-ji" tabindex="-1">存储层级 <a class="header-anchor" href="#cun-chu-ceng-ji" aria-label="Permalink to &quot;存储层级&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>log.dirs=/data/kafka-logs</span></span>
<span class="line"><span>└── orders-0/                    # Topic=orders, Partition=0</span></span>
<span class="line"><span>    ├── 00000000000000000000.log</span></span>
<span class="line"><span>    ├── 00000000000000000000.index</span></span>
<span class="line"><span>    ├── 00000000000000000000.timeindex</span></span>
<span class="line"><span>    ├── 00000000000001000000.log</span></span>
<span class="line"><span>    ├── 00000000000001000000.index</span></span>
<span class="line"><span>    └── leader-epoch-checkpoint</span></span></code></pre></div><table tabindex="0"><thead><tr><th>层级</th><th>说明</th></tr></thead><tbody><tr><td>Topic</td><td>逻辑消息分类</td></tr><tr><td>Partition</td><td>Topic 的物理分片，也是顺序性和并行度的基本单位</td></tr><tr><td>Log</td><td>一个 Partition 对应一条追加日志</td></tr><tr><td>Segment</td><td>Log 被切分成多个段文件，便于滚动、删除和查找</td></tr><tr><td>Record Batch</td><td>Producer 批量发送后的消息批次，Kafka 的实际写入单位</td></tr></tbody></table><h2 id="segment-wen-jian" tabindex="-1">Segment 文件 <a class="header-anchor" href="#segment-wen-jian" aria-label="Permalink to &quot;Segment 文件&quot;">​</a></h2><p>Kafka 不会把一个 Partition 写成单个巨大文件，而是拆成多个 Segment。每个 Segment 的文件名是该段的<strong>起始 Offset</strong>。</p><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>.log</code></td><td>保存实际消息数据</td></tr><tr><td><code>.index</code></td><td>Offset 到物理位置的稀疏索引</td></tr><tr><td><code>.timeindex</code></td><td>时间戳到 Offset 的稀疏索引</td></tr><tr><td><code>.txnindex</code></td><td>事务索引，用于过滤未提交或已中止事务</td></tr><tr><td><code>leader-epoch-checkpoint</code></td><td>Leader Epoch 与 Offset 映射，用于副本截断和故障恢复</td></tr></tbody></table><h3 id="segment-gun-dong" tabindex="-1">Segment 滚动 <a class="header-anchor" href="#segment-gun-dong" aria-label="Permalink to &quot;Segment 滚动&quot;">​</a></h3><p>常见滚动条件：</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>log.segment.bytes</code></td><td>Segment 达到指定大小后滚动</td></tr><tr><td><code>log.roll.ms</code> / <code>log.roll.hours</code></td><td>Segment 达到指定时间后滚动</td></tr><tr><td><code>log.index.size.max.bytes</code></td><td>索引文件达到上限后滚动</td></tr></tbody></table><p>只有当前活跃 Segment 会继续追加写入，旧 Segment 变为只读，后续可被清理或压缩。</p><h2 id="offset-yu-suo-yin" tabindex="-1">Offset 与索引 <a class="header-anchor" href="#offset-yu-suo-yin" aria-label="Permalink to &quot;Offset 与索引&quot;">​</a></h2><p>Kafka 的 Offset 是 Partition 内的逻辑编号，不是文件位置。读取某个 Offset 时，Kafka 需要把逻辑 Offset 转成 <code>.log</code> 文件里的物理位置。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标 Offset = 10023</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── 找到 baseOffset &lt;= 10023 的 Segment</span></span>
<span class="line"><span>  │     例如 00000000000001000000.log</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── 在 .index 中二分查找相近 Offset</span></span>
<span class="line"><span>  │     relativeOffset=23 -&gt; position=4096</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── 从 .log 的 position 顺序扫描到目标消息</span></span></code></pre></div><p>Kafka 的索引是<strong>稀疏索引</strong>，不是每条消息都有索引项。这样可以减少索引文件大小，查找时先定位到附近位置，再顺序扫描少量数据。</p><h2 id="page-cache" tabindex="-1">Page Cache <a class="header-anchor" href="#page-cache" aria-label="Permalink to &quot;Page Cache&quot;">​</a></h2><p>Kafka 依赖操作系统 Page Cache，而不是在 JVM 堆里缓存大量消息。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer 写入</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── Broker 追加写入文件</span></span>
<span class="line"><span>  ├── 数据先进入 OS Page Cache</span></span>
<span class="line"><span>  └── 由操作系统异步刷盘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Consumer 读取</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── 优先从 Page Cache 命中</span></span>
<span class="line"><span>  └── 未命中时再从磁盘读取</span></span></code></pre></div><p>这种设计的好处：</p><ul><li>避免 JVM 堆缓存导致 GC 压力过大</li><li>让操作系统统一管理缓存淘汰和预读</li><li>顺序写入配合 Page Cache 可以获得接近内存的读写性能</li><li>Broker 重启后 Page Cache 可以被操作系统逐步重新预热</li></ul><h2 id="shua-pan-ji-zhi" tabindex="-1">刷盘机制 <a class="header-anchor" href="#shua-pan-ji-zhi" aria-label="Permalink to &quot;刷盘机制&quot;">​</a></h2><p>Kafka 默认不在每条消息写入后强制 <code>fsync</code>，而是依赖操作系统刷盘。数据可靠性主要由<strong>副本机制</strong>保证，而不是单机同步刷盘保证。</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>log.flush.interval.messages</code></td><td>每写入多少条消息强制刷盘</td></tr><tr><td><code>log.flush.interval.ms</code></td><td>间隔多久强制刷盘</td></tr><tr><td><code>acks=all</code></td><td>等待 ISR 副本确认，提升集群级持久性</td></tr><tr><td><code>min.insync.replicas</code></td><td>限制最少同步副本数</td></tr></tbody></table><p>生产环境通常不建议频繁强制刷盘，否则会显著降低吞吐。更常见的做法是使用 <code>replication.factor=3</code>、<code>acks=all</code>、<code>min.insync.replicas=2</code>。</p><h2 id="ri-zhi-bao-liu" tabindex="-1">日志保留 <a class="header-anchor" href="#ri-zhi-bao-liu" aria-label="Permalink to &quot;日志保留&quot;">​</a></h2><p>Kafka 的消息消费后不会立即删除，而是按保留策略清理。</p><table tabindex="0"><thead><tr><th>策略</th><th>配置</th><th>说明</th></tr></thead><tbody><tr><td>按时间</td><td><code>log.retention.ms</code> / <code>log.retention.hours</code></td><td>超过保留时间后删除旧 Segment</td></tr><tr><td>按大小</td><td><code>log.retention.bytes</code></td><td>Partition 日志总大小超过阈值后删除旧 Segment</td></tr><tr><td>删除策略</td><td><code>cleanup.policy=delete</code></td><td>默认策略，直接删除过期 Segment</td></tr><tr><td>压缩策略</td><td><code>cleanup.policy=compact</code></td><td>按 Key 保留最新值，适合状态类 Topic</td></tr></tbody></table><h3 id="delete-yu-compact" tabindex="-1">Delete 与 Compact <a class="header-anchor" href="#delete-yu-compact" aria-label="Permalink to &quot;Delete 与 Compact&quot;">​</a></h3><p><code>delete</code> 适合普通事件流，例如订单事件、日志、埋点。消息超过保留时间后整段删除。</p><p><code>compact</code> 适合保存“当前状态”，例如用户配置、设备状态、维表数据。对于相同 Key，Kafka 最终只保留最新值。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Key=user-1, value=v1</span></span>
<span class="line"><span>Key=user-2, value=v1</span></span>
<span class="line"><span>Key=user-1, value=v2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Log Compaction 后：</span></span>
<span class="line"><span>Key=user-2, value=v1</span></span>
<span class="line"><span>Key=user-1, value=v2</span></span></code></pre></div><h2 id="xie-ru-lu-jing" tabindex="-1">写入路径 <a class="header-anchor" href="#xie-ru-lu-jing" aria-label="Permalink to &quot;写入路径&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── 批量压缩 Record Batch</span></span>
<span class="line"><span>  ├── 发送到 Partition Leader</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Broker Leader</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── 校验请求和权限</span></span>
<span class="line"><span>  ├── 追加写入 active Segment</span></span>
<span class="line"><span>  ├── 更新 LEO</span></span>
<span class="line"><span>  ├── 等待 Follower 拉取并进入 ISR 确认</span></span>
<span class="line"><span>  └── 推进 HW 后返回 ACK</span></span></code></pre></div><p>关键点：</p><ul><li>写入是追加模式，避免随机写</li><li>Broker 按 Partition 顺序写入，因此 Partition 内天然有序</li><li>Producer 批量发送，Broker 批量落盘</li><li>HW 之前的数据才对 Consumer 可见</li></ul><h2 id="du-qu-lu-jing" tabindex="-1">读取路径 <a class="header-anchor" href="#du-qu-lu-jing" aria-label="Permalink to &quot;读取路径&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Consumer Fetch(offset=N)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── Broker 根据 Offset 定位 Segment</span></span>
<span class="line"><span>  ├── 使用 .index 找到物理位置</span></span>
<span class="line"><span>  ├── 从 .log 顺序读取 Record Batch</span></span>
<span class="line"><span>  └── 返回不超过 HW 的消息</span></span></code></pre></div><p>Consumer 读取受两个 Offset 影响：</p><table tabindex="0"><thead><tr><th>Offset</th><th>说明</th></tr></thead><tbody><tr><td>LEO</td><td>当前副本写到的最新位置</td></tr><tr><td>HW</td><td>已被 ISR 确认的最高位置，普通 Consumer 最多读到这里</td></tr></tbody></table><p>事务场景下，如果 <code>isolation.level=read_committed</code>，Consumer 还会受到 LSO（Last Stable Offset）限制，避免读到未提交事务。</p><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#log" target="_blank" rel="noreferrer">Kafka Log</a></li><li><a href="https://kafka.apache.org/documentation/#persistence" target="_blank" rel="noreferrer">Kafka Design: Persistence</a></li><li><a href="https://kafka.apache.org/documentation/#topicconfigs" target="_blank" rel="noreferrer">Kafka Topic Configs</a></li></ul>`,43)])])}const g=e(p,[["render",d]]);export{u as __pageData,g as default};
